function solve(nums, queries) {
    const ans = [];
    for (const [li, ri, threshold] of queries) {
        const freq = {};
        for (let i = li; i <= ri; i++) {
            const num = nums[i];
            freq[num] = (freq[num] || 0) + 1;
        }
        let maxFreq = -1;
        let bestNum = -1;
        for (const numStr in freq) {
            const num = parseInt(numStr, 10);
            const count = freq[numStr];
            if (count >= threshold) {
                if (count > maxFreq || (count === maxFreq && num < bestNum)) {
                    maxFreq = count;
                    bestNum = num;
                }
            }
        }
        ans.push(bestNum === -1 ? -1 : bestNum);
    }
    return ans;
}

