#include <unordered_map>
#include <vector>

using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> ans;
    for (auto& q : queries) {
        long long li = q[0], ri = q[1], threshold = q[2];
        unordered_map<long long, int> freq;
        for (long long i = li; i <= ri; ++i) {
            freq[nums[i]]++;
        }
        long long max_freq = -1;
        long long best_num = -1;
        for (auto& [num, count] : freq) {
            if (count >= threshold) {
                if (count > max_freq || (count == max_freq && num < best_num)) {
                    max_freq = count;
                    best_num = num;
                }
            }
        }
        ans.push_back(best_num);
    }
    return ans;
}
